SELECT label_sizing, waist
FROM sizing_specifications
WHERE garment_type = 'pants';

SELECT size_id, MAX(date_modified) AS Latest_Modification_Date
FROM sizing_specifications
GROUP BY size_id;

SELECT label_sizing
FROM sizing_specifications
WHERE date_modified = (SELECT MAX(date_modified) FROM sizing_specifications);

SELECT "created_by", COUNT(*) AS "size_count"
FROM "sizing_specifications"
GROUP BY "created_by";

SELECT label_sizing, waist, back_crotch, inseam
FROM sizing_specifications
WHERE size_id = 1;

SELECT COUNT(*)
FROM sizing_specifications
WHERE created_by = (SELECT user_id FROM users WHERE username = 'John Doe');

SELECT label_sizing
FROM sizing_specifications
ORDER BY age_group ASC;

SELECT label_sizing, MIN(date_created) AS oldest_creation_date
FROM sizing_specifications
GROUP BY label_sizing;

SELECT AVG(back_crotch) AS Average_Back_Crotch_Measurement
FROM sizing_specifications
WHERE age_group = 'child';

SELECT label_sizing, waist, back_crotch, garment_type
FROM sizing_specifications
ORDER BY label_sizing DESC;
